// Extrai campos do payload da Evolution API (webhook v2 encapsula em $json.body)
const body = $json.body || $json;

const remoteJid = body?.data?.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net','').replace('@g.us','').replace('+','');
const msg = body?.data?.message || {};

return {
  event:     body.event || '',
  instance:  body.instance || '',
  phone:     phone,
  fromMe:    body?.data?.key?.fromMe || false,
  isGroup:   remoteJid.endsWith('@g.us'),
  messageId: body?.data?.key?.id || '',
  text:      msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || '',
  pushName:  body?.data?.pushName || '',
};

