// Detecta intenção a partir do texto simples (sem IA)
const text = ($input.first().json.text || '').toLowerCase().trim();

let intent = 'DESCONHECIDA';
let confidence = 0.0;

// IMPORTANTE: ordem importa — padrões mais específicos primeiro
const patterns = [
  ['SAUDACAO',  [/^(oi|ol[aá]|bom dia|boa tarde|boa noite|hey|eae|salve)/i]],
  ['REAGENDAR', [/remarcar|mudar|trocar|reagendar|outro dia|outro hor[aá]rio/i]],
  ['CANCELAR',  [/cancelar|desmarcar|n[aã]o vou|n[aã]o posso|anular/i]],
  ['CONSULTAR', [/minha consulta|pr[oó]xima|quando [eé]|quando vou|meus agendamentos|ver agendamentos/i]],
  ['AGENDAR',   [/agendar|marcar|quero.*consulta|preciso.*consulta|fazer.*consulta|nova consulta|quero marcar|preciso marcar/i]],
  ['INFO',      [/endere[çc]o|conv[eê]nio|pre[çc]o|valor|como funciona|funcionamento|hor[aá]rio de atendimento/i]],
  ['HUMANO',    [/atendente|humano|pessoa|algu[eé]m|recep[çc][aã]o|ligar/i]],
  ['CONFIRMAR', [/^(sim|s|yes|confirmo|confirmar|ok|pode ser|isso|exato)$/i]],
  ['NEGAR',     [/^(n[aã]o|nao|n|no|nunca|para)$/i]]
];

for (const [key, regs] of patterns) {
  for (const r of regs) {
    if (r.test(text)) { intent = key; confidence = 0.8; break; }
  }
  if (intent !== 'DESCONHECIDA') break;
}

// menu numérico
if (/^[1-6]$/.test(text)) {
  intent = { '1': 'AGENDAR', '2': 'CONSULTAR', '3': 'CANCELAR', '4': 'REAGENDAR', '5': 'INFO', '6': 'HUMANO' }[text];
  confidence = 0.95;
}

return { json: { ...$input.first().json, intent, confidence, normalizedText: text } };

// Dados originais da mensagem (preservados do nó de detecção de intenção)
const orig = $('Detecta Intenção').first().json;
const state = $input.first().json;  // conversation_state do postgres

const intent = orig.intent;
const pushName = orig.pushName || '';

let reply = '';

switch (intent) {
  case 'SAUDACAO':
  case 'DESCONHECIDA':
    reply = `Olá${pushName ? ', ' + pushName : ''}! 👋\n\nSou a assistente virtual da *Clínica Vida*. Como posso te ajudar hoje?\n\n*1️⃣* Agendar consulta\n*2️⃣* Ver meus agendamentos\n*3️⃣* Cancelar consulta\n*4️⃣* Remarcar consulta\n*5️⃣* Informações (endereço, convênios)\n*6️⃣* Falar com atendente\n\n_Digite o número da opção_`;
    break;
  case 'INFO':
    reply = `📍 *Clínica Vida*\n\n*Endereço:* Rua das Flores, 123 — Centro\n*Horário:* Seg-Sex 7h-19h · Sáb 7h-12h\n*Convênios:* Unimed, Amil, SulAmérica, Bradesco Saúde\n*Particular:* a partir de R$ 250\n\nQuer *agendar* agora? É só digitar *1*.`;
    break;
  case 'HUMANO':
    reply = `Vou te transferir para um atendente humano 👩‍💼\n\nPor favor, descreva brevemente o assunto enquanto aguardo. Em horário comercial o retorno é em até 5 minutos.`;
    break;
  case 'AGENDAR':
    reply = `Ótimo! Vamos agendar 😊\n\nQual especialidade você precisa?\n\n*1️⃣* Clínico Geral\n*2️⃣* Cardiologia\n*3️⃣* Dermatologia\n*4️⃣* Ginecologia\n*5️⃣* Pediatria\n*6️⃣* Ortopedia\n\nResponde com o número da especialidade.`;
    break;
  case 'CANCELAR':
    reply = `Sem problema. Vou listar seus agendamentos ativos...`;
    break;
  case 'REAGENDAR':
    reply = `Vamos remarcar! Primeiro deixa eu ver sua próxima consulta...`;
    break;
  case 'CONSULTAR':
    reply = `Vou checar sua agenda...`;
    break;
  default:
    reply = `Desculpa, não entendi 🤔\n\nDigite *menu* para ver as opções ou escolha um número de 1 a 6.`;
}

return { json: { ...orig, reply, conv_state: state.state } };

const row = $input.first().json;
const orig = $('Normalizar Payload').first().json;
const appts = row.appointments || [];

let reply;
if (!appts.length) {
  reply = 'Você não tem consultas agendadas no momento. 😊\n\nDigite *menu* para voltar ao início.';
} else {
  let lista = appts.map((a, i) => `*${i+1}.* ${a.specialty} com ${a.doctor}\n   📅 ${a.data} às ${a.hora}`).join('\n\n');
  reply = `Suas consultas agendadas:\n\n${lista}\n\nDigite o *número* da consulta que deseja cancelar ou *0* para voltar.`;
}

return { json: { ...orig, reply, appts } };

const row = $input.first().json;
const orig = $('Normalizar Payload').first().json;
const appts = row.appointments || [];

let reply;
if (!appts.length) {
  reply = 'Você não tem consultas agendadas no momento. 😊\n\nPara agendar, digite *1*.';
} else {
  const lista = appts.map((a, i) =>
    `*${i+1}.* ${a.specialty}\n   👨‍⚕️ ${a.doctor}\n   📅 ${a.data} às ${a.hora}`
  ).join('\n\n');
  const plural = appts.length === 1 ? 'consulta agendada' : 'consultas agendadas';
  reply = `Você tem *${appts.length} ${plural}*:\n\n${lista}\n\nDigite *menu* para voltar ao início.`;
}

return { json: { ...orig, reply, appts } };

const state = $input.first().json;          // conversation_state row
const orig  = $('Detecta Intenção').first().json; // intent original
const text  = (orig.text || '').trim();

let intent = orig.intent;

// Quando aguardando especialidade e usuário digita 1-6 → especialidade
if (state.state === 'AWAITING_SPECIALTY' && /^[1-6]$/.test(text)) {
  intent = 'SELECIONA_ESPECIALIDADE';
}
// Quando aguardando confirmação e usuário confirma/nega
if (state.state === 'AWAITING_CONFIRM') {
  if (/^(sim|s|yes|confirmo|ok|1)$/i.test(text)) intent = 'CONFIRMAR';
  if (/^(n[aã]o|nao|n|2|cancelar)$/i.test(text)) intent = 'NEGAR';
}
// "menu" sempre reseta
if (/^menu$/i.test(text)) intent = 'SAUDACAO';

return { json: { ...orig, intent, conv_state: state.state, conv_context: state.context } };

const data = $input.first().json;
const especialidades = {
  '1': { name: 'Clínico Geral',  duration: 30 },
  '2': { name: 'Cardiologia',    duration: 40 },
  '3': { name: 'Dermatologia',   duration: 30 },
  '4': { name: 'Ginecologia',    duration: 40 },
  '5': { name: 'Pediatria',      duration: 30 },
  '6': { name: 'Ortopedia',      duration: 40 },
};
const esp = especialidades[data.text] || { name: 'Clínico Geral', duration: 30 };
const newContext = { ...(data.conv_context || {}), specialty: esp.name, duration: esp.duration };
const reply = `Ótima escolha! *${esp.name}* ✅\n\nQual data você prefere?\nEx: *15/07* ou *amanhã*\n\n_(Atendemos Seg-Sex 7h-19h · Sáb 7h-12h)_`;

return { json: { ...data, reply, newState: 'AWAITING_DATE', newContext } };

parameters.query:
UPDATE conversation_state
SET state = 'AWAITING_DATE',
    context = jsonb_build_object(
      'specialty', '{{($json.newContext.specialty || "Clínico Geral").replace(/'/g, "''")}}',
      'duration',  {{$json.newContext.duration || 30}}
    ),
    last_intent  = 'SELECIONA_ESPECIALIDADE',
    last_seen_at = NOW(),
    expires_at   = NOW() + INTERVAL '30 minutes'
WHERE phone = '{{($json.phone || "").replace(/'/g, "''")}}';
SELECT state, phone FROM conversation_state WHERE phone = '{{($json.phone || "").replace(/'/g, "''")}}';

